#!/bin/bash
# Metadata-only split builder. Use directly for small manifests; use sbatch if
# the input hardness file is generated by a heavy model-evaluation pipeline.

set -euo pipefail

REPO_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../.." && pwd)"
cd "${REPO_ROOT}"

uv run python -m ihd.evaluation.build_benchmark_splits "$@"
